{
  "name": "South Carolina PACE (Program of All-Inclusive Care for the Elderly)",
  "eligibility": {
    "age": 55,
    "income_limits": "No financial criteria or income limits; no dollar amounts apply. Approximately 90% of participants are dually eligible for Medicare and Medicaid, but enrollment does not require Medicaid or Medicare[1][8].",
    "asset_limits": "No asset limits or financial criteria considered for PACE enrollment[1].",
    "other_requirements": [
      "Live in the service area of a South Carolina PACE organization[1][8].",
      "Certified by the state (SCDHHS) as meeting nursing home level of care[1][3][8].",
      "Able to live safely in the community with PACE services at time of enrollment[1][3].",
      "Not enrolled in Medicare Advantage (Part C), Medicare prepayment plan, Medicare prescription drug plan, or hospice[1]."
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Comprehensive care including all Medicare and Medicaid services, plus additional services to maintain community living: primary care, hospital care, prescription drugs, social services, restorative therapies, personal care, respite care, nutritional counseling, transportation, homemaker services, and adult day health care at PACE centers. No specific dollar amounts or hours stated; care is all-inclusive and individualized[1][3][8].",
    "varies_by": "region"
  },
  "application": {
    "methods": [
      "Contact SCDHHS or local PACE providers (specific phone/website not listed in sources; call SCDHHS Provider Service Center at (888) 289-0709 for guidance[8])",
      "Visit SCDHHS PACE page: https://www.scdhhs.gov/partners/managed-care/program-all-inclusive-care-elderly-pace[8]"
    ],
    "processing_time": "Not specified in sources",
    "waitlist": "Not specified in sources; may vary by PACE organization service area",
    "forms": [],
    "documents": [
      "Proof of age, residency in service area, and nursing home level of care certification (details not specified; prepare Medicare/Medicaid info if applicable)[1][3]"
    ]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Limited to service areas of specific PACE organizations in South Carolina (exact counties/providers not detailed in sources)[1][8].",
    "regional_variations": "Varies by PACE organization location, availability, and capacity; different providers serve different areas[1].",
    "offices_or_providers": ["SCDHHS-managed; contact via https://www.scdhhs.gov/partners/managed-care/program-all-inclusive-care-elderly-pace for local providers[8]"]
  },
  "official_source": "https://www.scdhhs.gov/partners/managed-care/program-all-inclusive-care-elderly-pace[8]",
  "gotchas": [
    "Must live in a specific PACE service area—not statewide[1][8].",
    "Requires state certification for nursing home level of care, even if not currently in a nursing home[1][3][8].",
    "Cannot be enrolled in Medicare Advantage, certain Medicare plans, or hospice[1].",
    "Voluntary enrollment; average participant is 76 with complex needs—may not suit all elderly[1].",
    "Sources lack specifics on SC providers, wait times, exact application steps—contact SCDHHS directly[8]."
  ],
  "data_shape_notes": "Not statewide; restricted to PACE organization service areas with regional providers. No income/asset test unique to PACE (unlike underlying Medicaid). Nursing home level of care certification required. Limited SC-specific details available."
}

{
  "name": "I-Care (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits. Available to all Medicare beneficiaries, their families, or caregivers. Must be eligible for Medicare (typically age 65+, disabled, or with ESRD).[2][3][4]",
    "asset_limits": "No asset limits or tests apply.[4]",
    "other_requirements": ["Medicare beneficiary or family/caregiver of one.", "South Carolina resident.[2][3][5]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Free one-on-one health insurance counseling; help enrolling in Medicare; comparing/changing Medicare Advantage and Part D plans; answering questions on Medigap protections; referrals to home care agencies or long-term care services; assistance with Medicare/Medicaid choices; review of Medicare Summary Notices or bills.[2][3][4][8][9]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-868-9095", "Contact local Area Agency on Aging (find by zip code via SHIP or AAA resources)", "In-person or referrals through Lt. Governor’s Office on Aging, 1301 Gervais Street, Suite 350, Columbia SC 29201.[3][5][7][8]"],
    "processing_time": "Immediate counseling available upon contact; no formal processing as it's not an entitlement program.[2][8]",
    "waitlist": null,
    "forms": ["No specific application forms required; counseling provided directly.[2][4]"],
    "documents": ["Medicare card, Medicare Summary Notice (MSN) or bills if applicable, personal information for plan options review.[2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "South Carolina residents only.[5]",
    "regional_variations": "Services accessible statewide via toll-free phone or local Area Agencies on Aging; no noted differences in services, but local AAAs handle in-person counseling which may vary by availability.[3][8]",
    "offices_or_providers": ["Lt. Governor’s Office on Aging (central office), local Area Agencies on Aging.[3][5][8]"]
  },
  "official_source": "https://aging.sc.gov/programs-initiatives/medicare-and-medicare-fraud",
  "gotchas": ["Not a direct benefits or financial assistance program—provides counseling and referrals only, not services or payments.", "Not Medicaid; confusable with SC Medicaid programs for elderly/disabled which have strict income/asset limits (e.g., $1,330/month single at 100% FPL).[1][3]", "Plans change annually; counseling needed yearly for updates.", "Funded federally, independent of insurance companies.[2][4][8]", "Volunteers often provide counseling; expertise from referrals by SSA/CMS.[8]"],
  "data_shape_notes": "no income test; counseling-only service for Medicare beneficiaries; delivered via statewide hotline and local AAAs; not an entitlement with waitlists or asset rules"
}

{
  "name": "SC Legal Help for Seniors",
  "eligibility": {
    "age": 60,
    "income_limits": "Not means-tested; no income or asset disclosure required for denial of services. Priority given to those with Greatest Economic Need (income at or below poverty line, generally 125%-200% of federal poverty guidelines in SC) or Greatest Social Need (non-economic factors like disabilities, language barriers, isolation). For referrals to SC Legal Services, household income typically at or below 125% of Federal Poverty Level, with some grant exceptions.[2][3]",
    "asset_limits": "No asset limits or tests; assets not used to deny services. SC Legal Services considers assets (e.g., bank accounts, property) for their referrals, with some grant exceptions allowing higher limits.[2][3]",
    "other_requirements": ["South Carolina resident", "Greatest economic or social need prioritized (low-income minorities, limited English proficiency, rural residents)", "U.S. citizen or eligible non-citizen for related benefits", "Targeted to OAA-specified senior populations"]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal advice and representation by attorneys in 11 areas: income protection, health care, long-term care, nutrition, housing, utilities, protective services, guardianship/defense against guardianship, abuse, neglect, age discrimination.[4]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: statewide intake at 1-888-346-5592 (toll-free) or 803-744-9430 (Columbia); Monday-Thursday 9am-6pm", "Online: Submit application via SC Legal Services online form (sclegal.org/services/)", "Local: Contact Area Agency on Aging offices or SCLS local offices for non-English/Spanish", "Referrals: From Area Agencies on Aging to SC Legal Services or SC Bar Pro Bono"],
    "processing_time": "Not specified in sources",
    "waitlist": null,
    "forms": ["Online application through SC Legal Services (LATIS intake system)"],
    "documents": ["Income and benefits info (for resource identification, not denial)", "Details on legal issue", "Proof of age/residency if requested"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Funded through 10 Area Agencies on Aging (e.g., Upper Savannah Region provides services); local offices handle intake for non-English speakers; examples of regional cases like estate recovery assistance.[4]",
    "offices_or_providers": ["Area Agencies on Aging throughout SC", "South Carolina Legal Services local offices"]
  },
  "official_source": "https://aging.sc.gov/programs-initiatives/legal-assistance-older-adults",
  "gotchas": ["Not means-tested, but prioritized by economic/social need—higher need gets served first", "No criminal cases; civil only", "Income/assets asked for referrals/resource matching, not denial", "Referrals to SC Legal Services if not qualifying under OAA (which has stricter 125% FPL)", "Must be provided by attorneys per state rules", "Resources inadequate for all seniors, so targeting applied"],
  "data_shape_notes": "No income/asset test for denial; priority-based via OAA targeting; delivered statewide via 10 Area Agencies on Aging with attorney requirement; referrals to means-tested programs like SCLS"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; services are free and available to all regardless of financial status.",
    "asset_limits": "No asset limits or tests apply.",
    "other_requirements": ["Resident must be in a long-term care facility (nursing homes, assisted living, community residential care facilities, DDSN or DMH facilities) in South Carolina.", "Complaint must relate to quality of care, quality of life, rights violations, abuse/neglect, transfers/discharges, or benefits assistance.", "Available to residents, family members, friends, facility staff, or any concerned individual."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Investigation and resolution of complaints; advocacy for resident rights; assistance with appeals/grievances; education on resident rights and benefits; information/referrals for long-term care services; mediation with facilities; promotion of dignity, respect, and quality care. No financial aid, hours, or dollar amounts provided.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Statewide toll-free 1-800-868-9095 (SCDOA LTCOP hotline for abuse/neglect suspicions or complaints).", "Regional offices (e.g., Santee-Lynches: (803)774-1983 or sbrooks@slcog.org; Appalachian COG: (864) 242-9733 or ombudintake@scacog.org).", "Email or walk-in to regional offices.", "State office: (803) 734-9900."],
    "processing_time": "Not specified; ombudsmen investigate promptly, determine validity, mediate resolution, and follow up.",
    "waitlist": null,
    "forms": ["No specific forms required; complaints filed via phone, email, or in-person."],
    "documents": ["No documents needed to file a complaint; provide details of the issue verbally or in writing. Confidentiality maintained unless permission given."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to long-term care facilities within South Carolina; covers 2,039 facilities statewide.",
    "regional_variations": "Administered statewide by SC Department on Aging through 10 regional offices (e.g., Santee-Lynches covers Clarendon, Lee, Kershaw, Sumter counties; Appalachian COG covers Anderson, Cherokee, Greenville, Oconee, Pickens, Spartanburg). Contact regional ombudsman for local issues; services consistent but intake contacts differ.",
    "offices_or_providers": ["10 regional offices via SC Department on Aging; state office at 1301 Gervais Street, Suite 350, Columbia, SC 29201."]
  },
  "official_source": "https://aging.sc.gov/programs-initiatives/long-term-care-ombudsman-program",
  "gotchas": ["Not a healthcare or financial benefits program—purely advocacy for resolving facility complaints; does not provide direct services like care or funding.", "Only for those already in long-term care facilities, not community-dwelling adults (separate reporting for community abuse).", "Complaints handled confidentially; identity not disclosed without permission, even if needed for resolution.", "Anyone can file, not just residents or family.", "No cost, but resolution depends on facility cooperation and complaint validity."],
  "data_shape_notes": "no income/asset/age test; advocacy-only for LTC facility residents statewide via 10 regional offices; complaint-driven, not application for ongoing benefits"
}

{
  "name": "Elderly Simplified Application Project (ESAP)",
  "eligibility": {
    "age": 60,
    "income_limits": "Total monthly income must not exceed the SNAP income limit for the household size (exact dollar amounts follow standard SNAP limits and are not specified uniquely for ESAP in available data; refer to current SNAP charts at DSS for precise figures by household size)",
    "asset_limits": "Not applicable (ESAP follows standard SNAP resource rules with no unique asset test specified; streamlined verification applies)",
    "other_requirements": [
      "All household members are 60 years or older",
      "No earned income (e.g., no salaries from work) in the household",
      "Household does not already receive SNAP benefits under South Carolina Combined Application Project (SCCAP)"
    ]
  },
  "benefits": {
    "type": "financial",
    "value": "SNAP benefits (EBT card for food purchases); certification period extended up to 36 months; benefits issued from date of application filing if eligible",
    "varies_by": "household_size"
  },
  "application": {
    "methods": [
      "Mail: Complete DSS ESAP Application (Form 16176 or DSS Form 16177 referenced) and send to ESAP, South Carolina Department of Social Services, PO Box 100203, Columbia, SC 29202",
      "Online assistance via partners like SC Thrive (scthrive.org/seniors)",
      "Simplified initial application with limited verification; annual one-page mail-in form (no recertification interview required)"
    ],
    "processing_time": "Notified in writing of decision; benefits from date filed if eligible (exact processing days not specified)",
    "waitlist": null,
    "forms": [
      "DSS ESAP Application (Form 16176)",
      "DSS Form 16177 (informational/brochure)"
    ],
    "documents": [
      "Limited verification of circumstances (e.g., income, identity; most verified electronically; specifics not detailed beyond simple application)"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Dedicated caseworker unit statewide; no specific regional differences in providers, offices, or wait times noted",
    "offices_or_providers": [
      "South Carolina Department of Social Services (central mailing: PO Box 100203, Columbia, SC 29202)",
      "Partners like SC Thrive and Benefits Data Trust (BDT) for application assistance"
    ]
  },
  "official_source": "https://dss.sc.gov/assistance-programs/snap/how-do-i-apply/help-for-the-elderly/",
  "gotchas": [
    "Excludes households already in SCCAP",
    "No earned income allowed (only unearned income like Social Security permitted)",
    "Must meet standard SNAP income limits (not waived)",
    "Not for households with children or child-only cases",
    "Simplifications like no interview apply, but still requires annual mail-in form",
    "Distinguish from SCCAP: ESAP is for elderly-only with no earnings"
  ],
  "data_shape_notes": "Streamlined SNAP demo for elderly-only households with no earnings; no unique income/asset tables (uses standard SNAP); extended certification to 36 months; no interview/recertification required; statewide with dedicated senior unit"
}

{
  "name": "Eldercare Trust Fund",
  "eligibility": {
    "age": null,
    "income_limits": "No direct eligibility for individuals; grants awarded only to non-profit organizations in South Carolina whose programs support older adults aging in place[3][4].",
    "asset_limits": "No asset limits apply, as this is not a direct benefit program for individuals[3][4].",
    "other_requirements": ["Non-profit organizations must propose innovative programs that help older adults remain in homes and communities with maximum independence and dignity[3][4]", "Programs must supplement, not replace, existing state services[3]"]
  },
  "benefits": {
    "type": "financial",
    "value": "Grants to non-profits for innovative services such as: training for first responders and caregivers on dementia/Alzheimer's; transportation programs; home modification programs; in-home mobility training for hearing/vision impairments; rapid Meals on Wheels for hospital discharges (bypassing long waitlists)[4][6]. Since 1992, over $580,000 awarded to more than 43 non-profits statewide[4].",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Not currently accepting applications for grants[4]", "Donations via SC State Income Tax Form Line 28 with I-330 Form, or check mailed to: South Carolina Department on Aging, 1301 Gervais Street, Suite 350, Columbia SC 29201[4]"],
    "processing_time": "Not applicable for individuals; grant application process details not currently available as applications are closed[4][5]",
    "waitlist": null,
    "forms": ["I-330 Form (for tax check-off donations)[4]"],
    "documents": ["For donations: none specified beyond tax form or check[4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; grants to non-profits statewide[3][4]",
    "regional_variations": "Programs funded vary by non-profit providers (e.g., The ARK of SC for dementia training in rural areas, Senior Resource Incorporated for rapid Meals on Wheels), but no specified differences in grant process or wait times by region[4][6]",
    "offices_or_providers": ["Administered statewide by South Carolina Department on Aging[3][4]"]
  },
  "official_source": "https://aging.sc.gov/programs-initiatives/eldercare-trust-fund[4]",
  "gotchas": ["Does not provide awards or services directly to individuals or families—only grants to non-profits[4]", "Common mistake: assuming it's a direct aid program like Medicaid; it's a grant fund for innovative community programs[3][4]", "Not currently accepting grant applications[4]", "Families must contact funded non-profits for services, which may have their own eligibility/waitlists (e.g., Meals on Wheels can take weeks/months without this funding)[6]"],
  "data_shape_notes": "Grants only to non-profits for innovative aging-in-place programs; no individual eligibility, income/asset tests, or direct applications—fund supplements existing services via community providers[3][4]"
}
